	ark_mili: {
		enable: "phaseUse",
		selectCard: -1,
		filterCard: function (card) {
			return get.is.visible(card);
		},
		usable: 1,
		discard: false,
		lose: false,
		content: function () {
			var num = cards.length;
			player.hideHandcard(cards);
			if (num % 2 == 0) player.addTempSkill(event.name + "_nodistance", { player: "useCardAfter" });
			else player.addTempSkill(event.name + "_extra", { player: "useCardAfter" });
		},
		subSkill: {
			extra: {
				mod: {
					selectTarget: function (card, player, range) {
						if (!get.is.instantCard(card)) return;
						if (range[1] == -1) return;
						range[1]++;
					},
					aiOrder: function (player, card, num) {
						var range = lib.filter.selectTarget(card, player);
						if (range < 0 || range[1] < 0) return 0;
						return player.getUseValue(card);
					}
				},
				sub: true
			},
			nodistance: {
				mod: {
					targetInRange: function (card) {
						if (_status._ark_mili_nomod) return;
						return true;
					},
				},
				sub: true
			},
		},
		ai: {
			order: function (item, player) {
				if (get.itemtype(player) == 'player') {
					var skills = player.getSkills(true).concat(lib.skill.global), cards = player.getCards('hs'), names = [], distance = 0, targets = 0;
					game.expandSkills(skills);
					for (var i = 0; i < skills.length; i++) {
						var ifo = get.info(skills[i]);
						if (ifo.viewAs && typeof ifo.viewAs != 'function' && player.hasUseTarget(ifo.viewAs)) {
							if (!ifo.viewAsFilter || ifo.viewAsFilter(player)) {
								names.add(ifo.viewAs.name);
							}
						}
						else {
							var hiddenCard = get.info(skills[i]).hiddenCard;
							if (typeof hiddenCard == 'function') {
								for (var i in lib.inpile) {
									if (hiddenCard(player, i) && player.hasUseTarget({ name: i })) {
										names.add(i);
									}
								}
							}
						}
					};
					for (i of cards) {
						if (player.hasUseTarget(i)) names.add(i.name);
					};
					for (i of names) {
						distance += game.countPlayer(function (target) {
							return player.canUse({ name: i }, target, false);
						});
						targets += game.countPlayer(function (target) {
							return player.canUse({ name: i }, target);
						});
					};
					var num = player.hasVisibleCard();
					if ((num % 2 == 0 && distance > targets) || (num % 2 != 0 && targets >= distance)) return 100;
				}
				return 7;
			},
			result: {
				player: 1
			},
		},
	},
