	//太傅
	"ark_zhilve": {
		audio: "ext:天灾之下/audio:2",
		mark: true,
		marktext: "略",
		intro: {
			name: "制略",
			content: function (storage, player, skill) {
				var tip = '重置技，出牌阶段限四次，你可以将一张';
				var list = player.getChongzhiji(skill);
				if (list.length < 2) {
					tip += '牌按以下规则使用：';
					if (!list.contains('club')) tip += '♣当【远交近攻】；';
					if (!list.contains('diamond')) tip += '♦当【洞烛先机】；';
					if (!list.contains('heart')) tip += '♥当【戮力同心】；';
					tip = tip.slice(0, -1) + '。';
				} else {
					if (!list.contains('club')) tip += '♣当【远交近攻】';
					else if (!list.contains('diamond')) tip += '♦当【洞烛先机】';
					else if (!list.contains('heart')) tip += '♥当【戮力同心】';
					tip += '使用，然后除非你弃置一张♠牌，否则你失去1点体力。';
				}
				return tip;
			}
		},
		chongzhiji: function (player, skill, item) {
			if (!player.storage[skill]) {
				player.storage[skill] = [];
			}
			player.storage[skill].add(item);
			if (!['club', 'diamond', 'heart'].contains(item)) return;
			if (player.storage[skill].length >= 3) {
				var now = game.createEvent('resetChongzhiji', false);
				now.player = player;
				now.skill = skill;
				now.setContent(function () {
					player.storage[skill] = [];
					player.markSkill(skill);
					event.trigger('resetChongzhiji');
				});
				var next = game.createEvent('ark_zhilve_reset');
				_status.event.next.remove(next);
				_status.event.after.push(next);
				next.player = player;
				next.setContent(function () {
					"step 0"
					var next = player.chooseToDiscard('he', { suit: 'spade' });
					next.set('ai', function (card) {
						return 8 - get.value(card);
					});
					next.set('prompt', '制略；弃置一张♠牌');
					next.set('prompt2', '或取消并失去一点体力');
					"step 1"
					if (!result.bool) {
						player.loseHp();
					}
				});
			} else {
				player.markSkill(skill);
			}
		},
		enable: "chooseToUse",
		usable: 4,
		filter: function (event, player) {
			var map = lib.skill['ark_zhilve'].cardnamePair;
			for (var p in map) {
				if (player.getChongzhiji('ark_zhilve').contains(p)) continue;
				if (event.filterCard(map[p], player, event) &&
					player.countCards('hs', { suit: p })) return true;
			}
			return false;
		},
		cardnamePair: {
			'club': { name: 'ark_yuanjiao' },
			'diamond': { name: 'dongzhuxianji' },
			'heart': { name: 'arkCard_lulitongxin' }
		},
		position: "hes",
		filterCard: function (card, player, event) {
			event = event || _status.event;
			var filter = event._backup.filterCard;
			var suit = get.suit(card, player);
			if (suit == 'spade') return false;
			if (player.getChongzhiji('ark_zhilve').contains(suit)) return false;
			var name = lib.skill['ark_zhilve'].cardnamePair[suit].name;
			return event._backup.filterCard({ name: name, cards: [card] }, player, event);
		},
		viewAs: function (cards, player) {
			return lib.skill['ark_zhilve'].cardnamePair[get.suit(cards[0], player)];
		},
		check: function (card) {
			var player = _status.event.player;
			var cardx = lib.skill['ark_zhilve'].cardnamePair[get.suit(card)];
			if (player.getUseValue(cardx, true, true) < 0) return 0;
			return 8 - get.value(card);
		},
		onuse: function (result, player) {
			var suit = get.suit(result.cards, player);
			player.changeChongzhiji('ark_zhilve', suit);
		},
		prompt: function (event) {
			return lib.skill['ark_zhilve'].intro.content(null, event.player, 'ark_zhilve');
		},
		ai: {
			threaten: 1.2,
			order: 1
		},
	},
	ark_boya: {
		trigger: { player: "phaseBegin" },
		logTarget: function () {
			return game.filterPlayer(function (current) {
				return current.isMinHandcard();
			});
		},
		check: function (e, player) {
			return game.filterPlayer(function (current) {
				return current.isMinHandcard() && get.attitude(player, current) > 0;
			}) > game.filterPlayer(function (current) {
				return current.isMinHandcard() && get.attitude(player, current) < 1;
			});
		},
		content: function () {
			"step 0"
			event.targets = game.filterPlayer(function (current) {
				return current.isMinHandcard();
			});
			for (var i of event.targets) i.draw("nodelay");
			"step 1"
			var target = event.targets.shift(), cards = target.getCards("h", function (card) {
				return get.tag(card, "damage");
			});
			event.cards = cards;
			event.target = target;
			if (target.isDamaged()) target.chooseBool("是否弃置所有伤害牌" + (cards.length ? ("（" + t(cards) + "）") : "") + "并回复一点体力？").set("choice", (cards.length && (cards.length < 2 || (player.hp < 2 && cards.length < 3))));
			"step 2"
			if (result.bool && cards.length) {
				target.discard(cards);
				target.recover();
			};
			if (event.targets.length) event.goto(1);
		},
	},
	//龙舌兰
	ark_liduan: {
		marktext: "断",
		intro: {
			markcount: function (num) {
				return (game.roundNumber - 1) - (num || 0);
			},
			content: function (num) {
				num = num || 0;
				return ((game.roundNumber - 1) - num) ? "已" + get.cnNumber((game.roundNumber - 1) - num) + "轮未发动〖立断〗" : "本轮已发动〖立断〗";
			},
		},
		audio: "ext:天灾之下/audio:2",
		group: "ark_liduan_round",
		enable: "phaseUse",
		usable: 1,
		filterTarget: function (e, player, target) {
			return target.getDiscardableCards(player, 'he').length;
		},
		content: function () {
			"step 0"
			player.discardPlayerCard(target, 1 + Math.min(4, ((game.roundNumber - 1) - (player.storage[event.name] || 0)) * 2), true);
			"step 1"
			game.broadcastAll(function (player) { player.storage[event.name] = game.roundNumber; }, player);
			player.unmarkSkill(event.name);
			if (result.links) {
				event.cards = result.links.filter(function (card) {
					return get.name(card) == "sha";
				});
				if (!event.cards.length && result.links.length > 1) {
					player.loseHp();
					event.finish();
				};
			} else event.finish();
			"step 2"
			if (event.cards.length > 1) {
				player.chooseCardButton("请选择要使用的【杀】", event.cards).ai = function (button) {
					return get.player().getUseValue(button.link);
				};
			} else if (event.cards.length == 1) event.card = event.cards[0];
			else event.finish();
			"step 3"
			var card = (event.card || result.links[0]);
			if (card) {
				player.chooseUseTarget(card, false);
				event.cards.remove(card);
			};
			if (event.cards.length) event.goto(2);
		},
		subSkill: {
			round: {
				trigger: {
					global: "roundStart"
				},
				silent: true,
				content: function () {
					var num = player.storage[event.subname()] || 0;
					player[(((game.roundNumber - 1) - num) ? '' : 'un') + 'markSkill'](event.subname());
				}
			},
		},
		ai: {
			order: function (item, player) {
				return get.order({ name: "sha" }, player) - 0.1;
			},
			result: {
				target: function (player, target) {
					//纪狗（
					var num = 1 + Math.min(4, ((game.roundNumber - 1) - (player.storage.ark_liduan || 0)) * 2);
					if (num >= target.num("h")) {
						if ((num > 1 ? player.hp > 2 : true) && player.hasSha()) return -101 - target.num("h");
						if (target.hasSha()) return -102 - target.num("h");
					};
					if (num < target.num("h") && (num > 1 ? player.hp > 2 : true) && (target.num("h") - num) < 4) return -100 + (target.num("h") - num);
				},
			},
		},
	},
