	//号角
	"ark_xuezhan": {
		audio: "ext:天灾之下/audio:4",
		trigger: {
			global: "useCardAfter"
		},
		direct: true,
		filter: function (event, player) {
			if (event.card.name != 'sha') return false;
			if (player != event.player && !event.targets.contains(player)) return false;
			if (game.hasPlayer2(function (current) {
				return current.getHistory('damage', function (evt) {
					return evt.card == event.card;
				}).length;
			})) return false;
			if (player == event.player) {
				return event.targets.length == 1;
			}
			return event.targets.contains(player);
		},
		content: function () {
			"step 0"
			var target = (player == trigger.player) ? trigger.targets[0] : player;
			var next = target.chooseToUse({
				filterCard: function (card, player, event) {
					if (get.name(card) != 'sha') return false;
					return lib.filter.filterCard.apply(this, arguments);
				},
				filterTarget: function (card, player, target) {
					if (target != _status.event.sourcex && !ui.selected.targets.contains(_status.event.sourcex)) return false;
					if (_status.event.getParent().player == player) {
						return lib.filter.targetEnabled.apply(this, arguments);
					}
					return lib.filter.filterTarget.apply(this, arguments);
				},
				complexSelect: true,
				nodistance: player != trigger.player,
				prompt: get.prompt('ark_xuezhan', trigger.player),
				prompt2: (player == trigger.player) ?
					get.translation(player) + '对你使用【杀】结算完后，若目标唯一且未造成伤害，除非你对其使用【杀】，否则其可以弃置你一张牌。' : '你为目标的【杀】结算完后，若未造成伤害，你可以对使用者使用【杀】（无距离限制）。',
				logSkill: ['ark_xuezhan', trigger.player],
				playerx: player,
				sourcex: trigger.player
			});
			if (player != trigger.player) event.goto(2);
			"step 1"
			if (!result.bool) {
				var next = player.discardPlayerCard(trigger.targets[0], 'he');
				next.set('ai', function (button) {
					if (_status.event.att > 0) return 0;
					return get.value(button.link);
				});
				next.set('prompt', get.prompt('ark_xuezhan', trigger.targets));
				next.set('prompt2', '你使用【杀】结算完后，若目标唯一且未造成伤害，除非目标对你使用【杀】，否则你可以弃置其一张牌。');
				next.set('logSkill', ['ark_xuezhan', trigger.targets]);
				next.set('att', get.attitude(player, trigger.targets[0]));
			}
			event.finish();
			"step 2"
			if (!result.bool && player.canUse({ name: 'sha' }, trigger.player, false)) {
				var next = player.chooseBool(
					'血战：你可以失去一点体力',
					'以视为对' + get.translation(trigger.player) + '使用【杀】'
				);
				next.set('ai', function () {
					if (!player.hasCard(function (card) {
						return get.tag(card, 'save') ||
							get.tag(card, 'recover');
					}, 'h') && player.hp < 2) return false;
					return get.effect(trigger.player, { name: 'sha' }, player, player) > 0;
				});
			} else event.finish();
			"step 3"
			if (result.bool) {
				player.logSkill('ark_xuezhan', trigger.player);
				player.loseHp();
				player.useCard({ name: 'sha', isCard: true }, trigger.player);
			}
		}
	},
