	"ark_wangong": {
		audio: "ext:天灾之下/audio:4",
		init: function (player) {
			player.storage['ark_wangong_ar'] = 0;
		},
		enable: "phaseUse",
		usable: 1,
		filter: function (event, player) {
			return player.countCards('he');
		},
		filterCard: true,
		position: "he",
		check: function (card) {
			var player = get.owner(card);
			var attackRange = player.getAttackRange();
			if (get.subtype(card) == 'equip1' && player.getCards('e').contains(card)) {
				var info = get.info(card).distance;
				if (info && info.attackFrom) attackRange -= info.attackFrom;
				if (attackRange < 0) attackRange = 0;
			}
			var canadd = false, cansub = false;
			game.countPlayer(function (current) {
				if (get.distance(player, current) == attackRange + 1) {
					if (player.canUse({ name: 'sha' }, current, true, true) &&
						get.effect(current, { name: 'sha' }, player, player > 0)) canadd = true;
				}
				if (get.distance(player, current) == attackRange - 1) {
					if (player.canUse({ name: 'sha' }, current, true, true) &&
						get.effect(current, { name: 'sha' }, player, player > 0)) cansub = true;
				}
			});
			if (get.type(card) == 'basic' && !canadd) return 0;
			if (get.type(card) != 'basic' && !cansub) return 0;
			return 7.5 - get.value(card);
		},
		discard: false,
		loseTo: "discardPile",
		visible: true,
		delay: 0.5,
		content: function () {
			"step 0"
			player.draw();
			player.storage['ark_wangong_ar'] += (get.type(cards[0]) == 'basic') ? 1 : -1;
			if (player.storage['ark_wangong_ar']) {
				player.addTempSkill('ark_wangong_ar');
			} else {
				player.removeSkill('ark_wangong_ar');
			}
			"step 1"
			var cardx = { name: 'sha', isCard: true };
			var next = player.chooseUseTarget(cardx);
			next.set('_get_card', cardx);
			next.set('filterTarget', function (card, player, target) {
				if (player.getAttackRange() != player.distanceTo(target)) return false;
				return lib.filter.targetEnabledx(card, player, target);
			});
			next.set('prompt', '挽弓：视为使用一张【杀】');
			next.set('prompt2', '（仅能指定到其距离等于你攻击范围的角色为目标）');
		},
		ai: {
			order: function () {
				return get.order({ name: 'sha' }) - 0.15;
			},
			result: {
				player: 1
			}
		},
		subSkill: {
			ar: {
				mark: true,
				marktext: "弓",
				intro: {
					name: "挽弓",
					content: function (storage) {
						if (storage < 0) return '你的攻击范围' + storage;
						return '你的攻击范围+' + storage;
					}
				},
				mod: {
					attackRange: function (player, num) {
						return num + player.storage['ark_wangong_ar'];
					}
				},
				onremove: function (player) {
					player.storage['ark_wangong_ar'] = 0;
				},
				sub: true
			}
		}
	},
	"ark_daigong": {
		audio: "ext:天灾之下/audio:2",
		trigger: {
			player: "useCardToPlayered"
		},
		direct: true,
		filter: function (event, player) {
			return event.card.name == 'sha' && event.target.countDiscardableCards(player, 'h');
		},
		content: function () {
			"step 0"
			var next = player.discardPlayerCard(trigger.target, 'h', [1, 2]);
			next.set('ai', function (button) {
				if (_status.event.att > 0) {
					if (ui.selected.buttons.length) return 0;
					return 4.5 - get.value(button.link);
				}
				return get.value(button.link);
			});
			next.set('prompt', get.prompt2('ark_daigong', trigger.target));
			next.set('logSkill', ['ark_daigong', trigger.target]);
			next.set('att', player.attitudeTo(trigger.target));
			"step 1"
			if (result.bool) {
				for (var card of result.cards) {
					if (get.name(card) == 'shan') {
						trigger.excluded.add(trigger.target);
						game.log(trigger.card, '对', trigger.target, '被无效了');
						break;
					}
				}
				var next = trigger.target.chooseBool('怠攻：你可以摸两张牌并展示之');
				next.set('ai', function () {
					if (trigger.target.hasCard(function (card) {
						return get.tag(card, 'recover');
					}, 'hs') || trigger.target.hp > 2) return true;
					if (trigger.target.hasCard(function (card) {
						return get.tag(card, 'save');
					}, 'hs')) return true;
					return false;
				});
				next.set('prompt2', '若摸到了【闪】，你会受到一点伤害');
			} else event.finish();
			"step 2"
			if (result.bool) {
				trigger.target.draw(2);
			} else event.finish();
			"step 3"
			if (result.length) {
				trigger.target.showCards(result);
				var hasShan = false;
				for (var card of result) {
					if (get.name(card) == 'shan') {
						hasShan = true;
						break;
					}
				}
				if (!hasShan) {
					var words = ['有破绽！', '痛击！'];
					if (trigger.target.hp == 1) words.push('将死。');
					player.say(words.randomGet());
					trigger.target.damage(player);
				}
			}
		},
	},
