	//////焰尾
	/*焰尾　3/3　卡西米尔
	
【赤流》
每轮限一次，你可以将一张红色牌当【闪】使用，然后摸一张牌。
若如此做，本轮下一次其他角色使用【杀】指定目标时，你可以取消此牌其他目标，你成为此牌唯一目标。
	
【焰心》
当你使用实体【杀】结算完后，若目标唯一，你可以令目标角色选择一项：①对你使用一张【杀】；②你视为对其再次使用此【杀】。
	
【红松》
主公技，其他同势力角色使用【杀】指定唯一目标后，你可以向其询问是否将使用者转移给你。
  */
	"ark_chiliu": {
		enable: "chooseToUse",
		filterCard: function (card, player) {
			return get.color(card) == "red";
		},
		viewAs: {
			name: "shan",
		},
		viewAsFilter: function (player) {
			if (player.hasSkill("ark_chiliu_no") || !player.countCards('hes', { color: "red" })) return false;
		},
		position: "hes",
		check: function (card) {
			return 8 - get.value(card);
		},
		onuse: function (l, player) {
			player.draw();
			player.addTempSkill("ark_chiliu_shift", "roundStart");
			player.addTempSkill("ark_chiliu_no", "roundStart");
		},
		ai: {
			order: 10,
			respondShan: true,
			skillTagFilter: function (player) {
				if (!player.countCards('hs', { color: "red" })) return false;
			},
		},
		subSkill: {
			no: {},
			shift: {
				trigger: {
					global: "useCardToPlayer"
				},
				filter: function (event, player) {
					return event.card.name == "sha" && event.player != player && event.parent.targets.filter(t => t != player).length;
				},
				prompt2: function (event, player) {
					return "取消" + window.t(event.card) + "的其他目标并令你成为此牌唯一目标";
				},
				logTarget: "player",
				content: function () {
					trigger.parent.targets = [player];
					trigger.parent.target = player;
					trigger.targets = [player];
					trigger.target = player
					player.removeSkill(event.name);
				},
				check: function (event, player) {
					var eff = 0;
					for (var i of event.targets) {
						eff += get.effect(i, event.card, event.player, player);
					};
					return eff < get.effect(player, event.card, event.player, player);;
				},
			},
		},
	},
	"ark_yanxin": {
		//audio:"ext:天灾之下/audio:2",
		trigger: {
			player: "useCardAfter"
		},
		direct: true,
		filter: function (event, player) {
			if (!player.countCards('h')) return false;
			return event.card.name == "sha" && event.cards && event.cards.length &&
				event.targets && event.targets.length == 1;
		},
		content: function () {
			"step 0"
			var next = player.chooseToDiscard('h');
			next.set('ai', function (card) {
				if (_status.event.eff < 0) return 0;
				if (_status.event.hs > 4 && _status.event.att <= 0) return 0;
				return 6 - get.value(card);
			});
			next.set('prompt', get.prompt2('ark_yanxin', trigger.targets[0]));
			next.set('logSkill', ['ark_yanxin', trigger.targets]);
			next.set('eff', get.effect(trigger.targets[0], trigger.card, player, player));
			next.set('att', get.attitude(player, trigger.targets[0]));
			next.set('hs', trigger.targets[0].countCards('h'));
			"step 1"
			if (result.bool) {
				trigger.targets[0].chooseToUse({
					filterCard: function (card, player, event) {
						if (get.name(card) != 'sha') return false;
						return lib.filter.filterCard.apply(this, arguments);
					},
					filterTarget: function (card, player, target) {
						if (target != _status.event.sourcex && !ui.selected.targets.contains(_status.event.sourcex)) return false;
						return lib.filter.filterTarget.apply(this, arguments);
					},
					prompt: '焰心：对' + get.translation(player) + '使用一张【杀】，或令' + get.translation(trigger.card) + '再对你使用一次',
					targetRequired: true,
					complexSelect: true,
					sourcex: player
				});
			} else event.finish();
			"step 2"
			if (result.bool !== true) {
				var cardx = get.autoViewAs(trigger.card);
				player.useCard(cardx, trigger.targets[0], false);
			}
		}
	},
	"ark_hongsong": {
		unique: true,
		zhuSkill: true,
		trigger: {
			global: "useCardToPlayer",
		},
		filter: function (event, player, n, skill) {
			return event.card.name == "sha" && event.parent.targets.length == 1 && player.hasZhuSkill(skill) && event.player != player && event.player.isSameGroup(player);
		},
		logTarget: "player",
		content: function () {
			'step 0'
			trigger.player.chooseBool("###" + get.prompt(event.name) + "###将" + t(trigger.card) + "的使用者改为" + t(player)).set("choice", trigger.targets[0] == trigger.player ? false : get.effect(trigger.targets[0], trigger.card, player, trigger.player) >= get.effect(trigger.targets[0], trigger.card, trigger.player, trigger.player));
			'step 1'
			if (result.bool) {
				trigger.player.popup("是");
				trigger.player = player;
				trigger.parent.player = player;
			};
		},
		check: function (event, player) {
			return get.effect(event.targets[0], event.card, player, player) >= get.effect(event.targets[0], event.card, event.player, player);
		},
	},
