	/////   断罪者         
	"ark_duanzui": {
		audio: "ext:天灾之下/audio:4",
		init: function (player) {
			player.storage['ark_duanzui_addDamage'] = [];
		},
		trigger: {
			player: "useCard"
		},
		filter: function (event, player) {
			return event.card.name == 'sha';
		},
		check: function (event, player) {
			if (!event.targets.length) return false;
			for (var target of event.targets) {
				if (player.attitudeTo(target) > 0) return false;
			}
			return true;
		},
		content: function () {
			"step 0"
			player.judge(function (card) {
				return 0;
			});
			"step 1"
			event.judgeResult = {
				suit: result.suit,
				type: get.type2(result.card),
				number: result.number
			};
			var next = player.judge(function (card) {
				var value = 0;
				if (get.suit(card) == event.judgeResult.suit) value += 1;
				if (get.type2(card) == event.judgeResult.type) value += 0.7;
				if (Math.abs(get.number(card) - event.judgeResult.number) <= player.hp) value += 1.3;
				return value;
			});
			"step 2"
			var next = game.createEvent('ark_duanzui_clear');
			event.next.remove(next);
			trigger.after.push(next);
			next.player = player;
			if (result.suit == event.judgeResult.suit) {
				game.log('精准！');
				trigger.directHit.addArray(game.filterPlayer());
			}
			var players = [];
			if (get.type2(result.card) == event.judgeResult.type) {
				game.log('沉默！');
				game.countPlayer(function (current) {
					if (player != current && !current.hasSkill('fengyin')) {
						players.push(current);
						current.addTempSkill('fengyin');
					}
				});
			}
			next.players = players;
			if (Math.abs(get.number(result.card) - event.judgeResult.number) <= player.hp) {
				game.log('暴击！');
				player.storage['ark_duanzui_addDamage'].push(trigger.card);
				next.card = trigger.card;
			}
			next.setContent(function () {
				for (var i = 0; i < this.players.length; i++) {
					this.players[i].removeSkill('fengyin');
				}
				if (card) player.storage['ark_duanzui_addDamage'].remove(card);
			});
		},
		group: ["ark_duanzui_addDamage"],
		subSkill: {
			addDamage: {
				charlotte: true,
				trigger: { source: "damageBegin1" },
				forced: true,
				filter: function (event, player) {
					if (player.storage['ark_duanzui_addDamage'].contains(event.card)) {
						if (event.player.hp >= player.hp) return true;
					}
					return false;
				},
				content: function () {
					trigger.num++;
				},
				sub: true
			}
		}
	},
	"ark_tianqi": {
		audio: "ext:天灾之下/audio:2",
		trigger: {
			global: "judgeBegin"
		},
		direct: true,
		filter: function (event, player) {
			if (player.hasSkill('ark_tianqi_off')) return false;
			return player.countCards('h') > 0;
		},
		checkx: function (event, player) {
			var isEnemy = player.attitudeTo(event.player) <= 0;
			var hs = player.countCards('h', function (card) {
				return get.value(card) < 7;
			});
			var currentNode = ui.cardPile.firstChild;
			var pos = 0, bestPos = 0, maxJudge = 0;
			while (hs) {
				hs--; pos++;
				let temp = event.judge(currentNode);
				if (isEnemy) temp *= -1;
				if (temp > maxJudge) {
					maxJudge = temp;
					bestPos = pos;
				}
				currentNode = currentNode.nextSibling;
				if (!currentNode) break;
			}
			return bestPos;
		},
		content: function () {
			"step 0"
			/*我实在不知道怎么让ai提前知道本次判定有没有改的必要，所以干脆给ai加了个透视*/
			var next = player.chooseCard('h', [1, Infinity]);
			next.set('ai', function (card) {
				if (_status.event.bestNum <= ui.selected.cards.length) {
					return 0;
				}
				return 7 - get.value(card);
			});
			next.set('prompt', get.prompt2('ark_tianqi'));
			next.set('bestNum', lib.skill['ark_tianqi'].checkx(trigger, player));
			"step 1"
			if (result.bool) {
				player.addTempSkill('ark_tianqi_off', 'roundStart');
				player.logSkill('ark_tianqi');
				player.lose(result.cards, ui.ordering);
				event.cards = result.cards;
				event.count = event.cards.length;
				player.storage['ark_tianqi_draw'] = event.count;
				player.addTempSkill('ark_tianqi_draw');
			} else event.finish();
			"step 2"
			if (event.cards.length) {
				var cardx = event.cards.pop();
				var place = Math.floor(Math.random() * ui.cardPile.childNodes.length);
				ui.cardPile.insertBefore(cardx, ui.cardPile.childNodes[place]);
				event.redo();
			} else game.updateRoundNumber();
			"step 3"
			var cards = get.cards(event.count);
			game.cardsGotoOrdering(cards);
			var next = player.chooseToMove();
			next.set('list', [
				['牌堆顶', cards],
				['牌堆底'],
			]);
			next.set('prompt', '天启：点击将牌移动到牌堆顶或牌堆底');
			next.set('processAI', function (list) {
				var cards = list[0][1], player = _status.event.player;
				var top = [];
				var evt = _status.event.getParent('judge');
				if (evt && evt.judge) {
					var addition = get.attitude2(evt.player) > 0 ? 1 : -1;
					var bestPos = 0, bestResult = 0;
					for (var i = 0; i < cards.length; i++) {
						let tempResult = evt.judge(cards[i]) * addition;
						if (tempResult > bestResult) {
							bestResult = tempResult;
							bestPos = i;
						}
					}
					top = top.concat(cards.splice(bestPos, 1));
				}
				for (var i = 0; i < cards.length; i++) {
					if (get.value(cards[i]) >= 7) continue;
					top = top.concat(cards.splice(i--, 1));
				}
				var bottom = cards;
				return [top, bottom];
			});
			"step 4"
			var top = result.moved[0];
			var bottom = result.moved[1];
			top.reverse();
			console.log(top.length);
			console.log(top);
			for (var i = 0; i < top.length; i++) {
				ui.cardPile.insertBefore(top[i], ui.cardPile.firstChild);
			}
			for (i = 0; i < bottom.length; i++) {
				ui.cardPile.appendChild(bottom[i]);
			}
			player.popup(get.cnNumber(top.length) + '上' + get.cnNumber(bottom.length) + '下');
			game.log(player, '将' + get.cnNumber(top.length) + '张牌置于牌堆顶');
			game.updateRoundNumber();
			game.delayx();
		},
		subSkill: {
			draw: {
				audio: "ark_tianqi",
				marktext: "启",
				intro: {
					name: "天启",
					content: "本回合结束时，你从牌堆底摸&张牌"
				},
				init: function (player) {
					player.markSkill('ark_tianqi_draw');
				},
				onremove: true,
				trigger: { global: "phaseEnd" },
				forced: true,
				content: function () {
					"step 0"
					player.draw(player.storage['ark_tianqi_draw'], 'bottom');
				},
				sub: true
			},
			off: { sub: true }
		}
	},
