	////林雨霞
	"ark_jusha": {
		audio: "ext:天灾之下/audio:3",
		mod: {
			cardDiscardable: function (card, player) {
				if (card.hasGaintag('ark_jusha')) return false;
			}
		},
		locked: false,
		enable: ["chooseToUse", "chooseToRespond"],
		hiddenCard: function (player, name) {
			if (name == 'sha' && !player.hasCard(function (card) {
				return get.itemtype(card) == 'card' && card.hasGaintag('ark_jusha');
			}, 'h') && lib.inpile.contains(name)) return true;

		},
		filter: function (event, player) {
			if (event.responded || event.ark_jusha) return false;
			if (player.hasCard(function (card) {
				return get.itemtype(card) == 'card' && card.hasGaintag('ark_jusha');
			}, 'h')) return false;
			if (get.centerArea({ color: 'black' }).length < 2) return false;
			return event.filterCard({ name: 'sha' }, player, event);
		},
		delay: false,
		content: function () {
			"step 0"
			var evt = event.getParent(2);
			evt.set('ark_jusha', true);
			var cards = get.centerArea({ color: 'black' });
			var next = player.chooseButton(['聚沙：获得中央区两张黑色牌，视为' + (evt.name == 'chooseToUse' ? '使用' : '打出') + '【杀】', cards]);
			next.set('selectButton', 2);
			next.set('ai', function (button) {
				var evt = _status.event.getParent(3);
				var tmp = _status.event;
				_status.event = evt;
				var result = 1;
				var ai = evt.ai || event.ai1;
				if (typeof ai == 'function') {
					result = ai({ name: 'sha' }, _status.event.player, evt);
				}
				_status.event = tmp;
				if (typeof result == 'number' && result > 0) return get.value(button.link);
				return 0;
			});
			"step 1"
			var evt = event.getParent(2);
			if (result.bool && result.links && result.links.length) {
				player.gain(result.links, 'draw').set('gaintag', ['ark_jusha']);
				if (evt.name == 'chooseToUse') {
					game.broadcastAll(function (result, name) {
						lib.skill.ark_jusha_backup.viewAs = { name: name, isCard: true };
						lib.skill.ark_jusha_backup.prompt = '选择【杀】的目标';
					}, result.links[0], 'sha');
					evt.set('_backupevent', 'ark_jusha_backup');
					evt.backup('ark_jusha_backup');
				} else {
					delete evt.result.skill;
					delete evt.result.used;
					evt.result.card = { name: 'sha' };
					evt.redo();
					return;
				}
			}
			evt.goto(0);
		},
		ai: {
			effect: {
				target: function (card, player, target, effect) {
					if (get.tag(card, 'respondSha')) return 0.7;
				}
			},
			order: 11,
			respondSha: true,
			result: {
				player: 1
			}
		},
		subSkill: {
			backup: {
				sourceSkill: "ark_jusha",
				precontent: function () {
					delete event.result.skill;
					if (player.hasSkill('ark_jusha_notfirst')) {
						var next = player.loseHp();
						event.next.remove(next);
						event.parent.after.push(next);
					} else {
						player.addTempSkill('ark_jusha_notfirst', 'roundStart');
					}
				},
				filterCard: function () { return false },
				selectCard: -1,
				sub: true
			},
			notfirst: { sub: true }
		}
	},
	"ark_miying": {
		audio: "ext:天灾之下/audio:2",
		trigger: {
			global: "phaseJieshu"
		},
		direct: true,
		filter: function (event, player, onrewrite) {
			if (game.hasPlayer(function (current) {
				return current.hasHistory('useCard', function (evt) {
					return evt.targets && evt.targets.contains(player);
				});
			})) return false;
			return _status.currentPhase.countUsed(null, true) > 0;
		},
		content: function () {
			"step 0"
			event.cards = get.centerArea({ color: 'black' });
			event.count = _status.currentPhase.countUsed(null, true);
			"step 1"
			if (event.count > 0) {
				var next = player.chooseButton(['密影：选择要从中央区分配出去的牌（还可分配' + get.cnNumber(event.count) + '张）', event.cards, 'hidden']);
				next.set('selectButton', [1, event.count]);
				next.set('filterButton', function (button) {
					return get.position(button.link, true) == 'd';
				});
				next.set('ai', function (button) {
					if (ui.selected.buttons.length > 0) return 0;
					return get.value(button.link);
				});
			} else event._result = { bool: false };
			"step 2"
			if (result.bool) {
				if (!event.isFirst) {
					player.logSkill('ark_miying');
					event.isFirst = true;
				}
				event.thatCards = result.links.slice(0);
				var next = player.chooseTarget(true);
				next.set('ai', function (target) {
					if (_status.event.player.attitudeTo(target) <= 0) return 0;
					if (!target.countCards('h')) return 1;
					return get.value(_status.event.cards, target);
				});
				next.set('prompt', '密影：选择一名角色');
				next.set('prompt2', '获得' + get.translation(event.thatCards));
				next.set('cards', event.thatCards);
			} else event.finish();
			"step 3"
			if (result.bool) {
				event.count -= event.thatCards.length;
				var target = result.targets[0];
				target.gain(event.thatCards, player, 'give');
				target.addSkill('ark_miying_retain');
				if (!target.storage['ark_miying_retain'][player.playerid]) {
					target.storage['ark_miying_retain'][player.playerid] = 0;
				}
				target.storage['ark_miying_retain'][player.playerid] += event.thatCards.length;
				player.line(target, 'green');
			}
			event.goto(1);
		},
		subSkill: {
			retain: {
				charlotte: true,
				init: function (player, skill) {
					if (!player.storage['ark_miying_retain']) {
						player.storage['ark_miying_retain'] = {};
					}
				},
				onremove: true,
				trigger: { global: "phaseBegin" },
				forced: true,
				silent: true,
				filter: function (event, player) {
					return player.storage['ark_miying_retain'][event.player.playerid];
				},
				content: function () {
					"step 0"
					var num = player.storage['ark_miying_retain'][trigger.player.playerid];
					delete player.storage['ark_miying_retain'][trigger.player.playerid];
					if (!Object.keys(player.storage['ark_miying_retain']).length) {
						player.removeSkill('ark_miying_retain');
					}
					if (num) {
						var next = player.chooseToDiscard(num, true, 'h');
						next.set('prompt', '密影：请弃置' + get.cnNumber(num) + '张手牌');
					}
				},
				sub: true
			}
		}
	},
