	"ark_wuyue": {
		//audio:"ext:天灾之下/audio:2",
		enable: "phaseUse",
		usable: 1,
		filter: function (event, player) {
			return player.previous.previous.countCards('he') ||
				player.previous.countCards('he') ||
				player.next.countCards('he') ||
				player.next.next.countCards('he');
		},
		chooseButton: {
			dialog: function (event, player) {
				var dialog = ui.create.dialog(get.prompt('ark_wuyue'));
				var leftPlayers = [player.previous, player.previous.previous];
				if (game.players.length > 3) {
					dialog.add('上两家');
					dialog.add(leftPlayers);
					var rightPlayers = [player.next, player.next.next];
					dialog.add('下两家');
					dialog.add(rightPlayers);
				} else {
					dialog.add('就这两家');
					dialog.add(leftPlayers);
				}
				return dialog;
			},
			chooseControl: function (event, player) {
				return ['上两家', 'cancel2', '下两家'];
			},
			check: function (event, player) {
				if (game.players.length < 4) return '上两家';
				var Vacillate = 0, previous = player, next = player;
				for (var i = 0; i < 2; i++) {
					previous = previous.previous;
					next = next.next;
					if (player.attitudeTo(previous) < 0) Vacillate++;
					if (player.attitudeTo(next) < 0) Vacillate--;
				}
				return (Vacillate < 0) ? '上两家' : '下两家';
			},
			backup: function (result) {
				var next = get.copy(lib.skill['ark_wuyue_contentx']);
				next.isLeft = (result.control == '上两家');
				return next;
			},
		},
		ai: {
			order: 10,
			result: {
				player: function (player) {
					return 1;
				}
			}
		},
		subSkill: {
			contentx: {
				audio: "ark_wuyue",
				content: function () {
					"step 0"
					event.Alist = []; event.Blist = [];
					var previous = player, next = player;
					if (lib.skill['ark_wuyue_backup'].isLeft) {
						for (var i = 0; i < 2; i++) {
							previous = previous.previous;
							next = next.next;
							event.Alist.push(previous);
							event.Blist.push(next);
						}
					} else {
						for (var i = 0; i < 2; i++) {
							previous = previous.previous;
							next = next.next;
							event.Blist.push(previous);
							event.Alist.push(next);
						}
					}
					player.line(event.Alist, 'green');
					"step 1"
					event.current = event.Alist.shift();
					event.target = event.Blist.shift();
					event.current.draw('nodelay');
					var next = event.current.chooseToDiscard('h', true);
					next.set('ai', function (card) {
						if (_status.event.att < 0) {
							if (get.color(card) == 'red') return 13 - get.value(card);
						}
						return 10 - get.value(card);
					});
					next.set('prompt2', get.translation(event.target) + '本回合不能使用或打出该颜色的牌');
					next.set('att', get.attitude(event.current, event.target));
					"step 2"
					if (result.bool) {
						var color = get.color(result.cards[0]);
						event.current.line(event.target, (color == 'red') ? 'fire' : 'thunder');
						event.target.addTempSkill('ark_wuyue_' + color);
					}
					"step 3"
					if (event.Alist.length && event.Blist.length) event.goto(1);
				}
			},
			black: {
				charlotte: true,
				mark: true,
				marktext: "舞",
				intro: {
					name: "舞乐",
					content: "你本回合不能使用或打出黑色牌"
				},
				mod: {
					cardEnabled2: function (card, player) {
						if (get.color(card) == 'black') return false;
					}
				},
				onremove: true,
				sub: true
			},
			red: {
				charlotte: true,
				mark: true,
				marktext: "乐",
				intro: {
					name: "舞乐",
					content: "你本回合不能使用或打出红色牌"
				},
				mod: {
					cardEnabled2: function (card, player) {
						if (get.color(card) == 'red') return false;
					}
				},
				onremove: true,
				sub: true
			},
			none: { sub: true }
		}
	},
