				if (target.mayHaveShan() && !player.hasSkillTag('directHit_ai', true, {
					target: target,
					card: card,
				}, true)) return false;
				if (player.hasSkill('jueqing') || player.hasSkill('gangzhi') || target.hasSkill('gangzhi')) return false;
				return true;
