	ark_wuzhong: {
		enable: 'phaseUse',
		limited: true,
		skillAnimation: true,
		animationColor: 'gray',
		filterTarget: function (card, player, target) {
			return target.countCards() != player.countCards();
		},
		content: function () {
			'step 0'
			if (player.countCards() > 2) player.chooseToDiscard(player.countCards() - 2, true);
			player.drawTo(2);
			if (target.countCards() > 2) target.chooseToDiscard(target.countCards() - 2, true);
			target.drawTo(2);
			player.getStat().card = {};
			player.awakenSkill(event.name);
			var num = Array.from(Array(target.hp)).map(function (_, item) {
				return item + 1;
			});
			if (target.hp < 11) player.chooseControl(num).set('prompt', '请选择要声明的数值').set('ai', function () {
				var player = get.player();
				var card = player.getMaxCard('get.number(card,this)');
				var num = get.number(card), list = _status.event.list;
				if (num > 10) return list[list.length - 1] + 1;
				return player.hp;
			}).set('list', num); else {
				var id = lib.status.videoId++;
				game.broadcastAll(function (player, target, id) {
					if (game.me.playerid == player.playerid) {
						var dialog = ui.create.dialog('无终', 'forcebutton');
						dialog.videoId = id;
						dialog.addText('请' + (target.hp > 30 ? '输入' : '选择') + '要声明的数值' + (target.hp > 30 ? '(最大值为' + target.hp + ')' : ''));
						var buttons = ui.create.div('.buttons', dialog.content);
						if (target.hp < 31) {
							for (var i = 1; i < target.hp + 1; i++) {
								var number = ui.create.div('.shadowed.reduce_radius.pointerdiv.tdnode', '' + i);
								number.style.cursor = 'pointer';
								number.link = i;
								for (var j in lib.element.button) {
									number[j] = lib.element.button[j];
								};
								number.addEventListener(lib.config.touchscreen ? 'touchend' : 'click', ui.click.button);
								dialog.buttons.add(number);
								buttons.appendChild(number);
							};
							dialog.add([buttons, '']);
						} else {
							var input = ui.create.node('input.shadowed.reduce_radius.pointerdiv.tdnode',
								{ border: 'none' }
							), ok = ui.create.div('.shadowed.reduce_radius.pointerdiv.tdnode', '确定', function () {
								ui.selected.buttons = [{ link: Number(input.value) }];
								ui.click.ok();
							});
							input.value = target.hp;
							input.defaultValue = get.translation('sha');
							input.max = target.hp;
							input.onmouseover = function (e) {
								if (this.value == this.defaultValue) {
									this.value = "";
								};
								this.focus();
								this.select();
							};
							input.onclick = function (e) {
								if (this.value == this.defaultValue) {
									this.value = "";
								};
							};
							input.onblur = function () {
								if (!this.value || this.value.length <= 0) {
									this.value = this.defaultValue;
								} else this.defaultValue = this.value;
							};
							input.onkeydown = function (e) {
								if (e.keyCode == (lib.config.touchscreen ? 13 : 32)) {
									ui.selected.buttons = [{ link: Number(this.value) }];
									e.preventDefault();
									ui.click.ok();
								};
							};
							input.onkeyup = function () {
								if (!isNumber(this.value)) this.value = this.value.slice(0, -1);
								if (Number(this.value) > this.max) this.value = this.max;
							};
							input.focus();
							buttons.appendChild(input);
							buttons.appendChild(ok);
						};
					};
				}, player, target, id);
				player.chooseButton([0, 1], function (button) {
					var player = get.player();
					var card = player.getMaxCard('get.number(card,this)');
					var num = get.number(card);
					if (num > 10) return button.link;
					return button.link == player.hp && player.hp;
				}).set('dialog', id).set('closeDialog', true);
			};
			'step 1'
			var num = (result.links && result.links[0]) || result.control || target.hp;
			event.number = num;
			if (num) {
				player.popup(get.cnNumber(num, true));
				game.log(player, '声明的数值为', get.cnNumber(num, true));
				player.line(target, 'fire');
				target.chooseControlList(
					['弃置所有手牌并令' + get.translation(player) + '摸' + get.cnNumber(num) + '张牌',
					'双方亮出手牌并计算各自点数总和，赢的角色对没赢的角色造成' + get.cnNumber(num) + '点伤害']
				).set('ai', function () {
					var num = 0, player = get.player(), number = _status.event.number;
					player.getCards('h', function (card) {
						num += get.number(card);
					});
					if (num < 16 && number >= player.hp) return 0;
					return 1;
				}, true).set('number', num);
				event.cards = [player.getCards('h'), target.getCards('h')];
			} else event.finish();
			'step 2'
			if (result.index == 0) {
				target.discard(target.getCards('h'));
				player.draw(event.number);
				event.finish();
			};
			if (result.index == 1) {
				var id = lib.status.videoId++;
				game.broadcastAll(function (id, player, target) {
					var dialog = ui.create.dialog('无终', 'forcebutton');
					dialog.videoId = id;
					dialog.add(get.translation(player) + '的手牌');
					dialog.add(player.getCards('h'));
					dialog.add(get.translation(target) + '的手牌');
					dialog.add(target.getCards('h'));
				}, id, player, target);
				game.log(player, '展示了（', cards[0], '）');
				game.log(target, '展示了（', cards[1], '）');
				game.delay(2, 3);
				event.videoId = id;
			};
			'step 3'
			game.broadcastAll('closeDialog', event.videoId);
			var num = 0, num2 = 0, i;
			for (i of cards[0]) num += get.number(i);
			for (i of cards[1]) num2 += get.number(i);
			if (num > num2) {
				player.popup('胜');
				target.damage(event.number, player);
			}
			else if (num2 > num) {
				target.popup('胜');
				player.damage(event.number, target);
			} else {
				player.popup('平');
				target.popup('平');
			};
		},
		ai: {
			order: 4,
			result: {
				target: function (player, target) {
					if (get.damageEffect(target, player, player) > 0) {
						var card = player.getMaxCard('get.number(card,this)');
						var num = get.number(card);
						if (num > 11) return -(target.hp + target.countCards('h'));
					};
					return 0;
				},
			},
		},
	},
