	"ark_tianping2": {
		trigger: {
			player: "phaseDrawEnd",
		},
		direct: true,
		prompt: function () {
			var player = get.player();
			var list = game.filterPlayer(function (target) {
				return target != player && target.hasZhuSkill('ark_tianping', player) && (target.isSameGroup(player));
			});
			var str = '将两张手牌交给' + get.translation(list);
			if (list.length > 1) str += '中的一人';
			str += '并回复一点体力';
			return str;
		},
		filter: function (event, player) {
			return player.countCards('h') >= 2 && game.hasPlayer(function (current) {
				return current != player && current.hasZhuSkill('ark_tianping', player) && (current.isSameGroup(player));
			});
		},
		content: function () {
			'step 0'
			var list = game.filterPlayer(function (target) {
				return target != player && target.hasZhuSkill('ark_tianping', player) && (target.isSameGroup(player));
			});
			var str = '将两张手牌交给' + get.translation(list);
			if (list.length > 1) str += '中的一人';
			str += '并回复一点体力';
			if (list.length > 1) {
				player.chooseCardTarget({
					prompt: str,
					filterTarget: function (target) {
						return target != player && target.hasZhuSkill('ark_tianping', player) && target.isSameGroup(player);
					},
					selectCard: 2,
					ai1: function (card) {
						return 9 - get.value(card);
					},
					ai2: function (target) {
						return get.recoverEffect(get.player()) > 0 && get.attitude(player, target);
					},
				});
			} else {
				event.target = list[0];
				player.chooseCard(str, 2).set('ai', function () {
					return get.recoverEffect(get.player()) > 0 && get.attitude(get.player(), event.target);
				});
			}
			'step 1'
			if (result.bool) {
				player.line(event.target);
				event.target.gain(result.cards, player, 'giveAuto');
				player.recover(event.target);
			}
		},
	},
