	//特蕾西娅
	"ark_xingdeng": {
		audio: "ext:天灾之下/audio:2",
		mod: {
			aiValue: function (player, card, num) {
				if (player.hasVisibleCard() == 1) {
					var hs = player.countCards('h');
					if (get.is.visible(card)) return num / 4 * hs;
				}
			}
		},
		trigger: {
			global: "phaseJieshu"
		},
		forced: true,
		filter: function (event, player) {
			return player.hasVisibleCard() != 1;
		},
		content: function () {
			"step 0"
			var vs = player.getCards('h', (card) => get.is.visible(card));
			if (vs.length) player.hideHandcard(vs);
			"step 1"
			var hs = player.countCards('h');
			if (hs > 4) {
				var next = player.chooseToDiscard('h', hs - 4, true);
				next.set('prompt', '星灯：将手牌弃置至四张');
			} else player.drawTo(4);
			"step 2"
			var next = player.chooseCard('h', true);
			next.set('filterCard', function (card) {
				return !get.is.visible(card);
			});
			next.set('ai', function (card) {
				return 5.5 - Math.abs(5.5 - get.value(card));
			});
			next.set('prompt', '星灯：请明置一张牌');
			"step 3"
			if (result.bool) {
				player.viewHandcard(result.cards);
			}
		},
		ai: {
			effect: {
				target: function (card) {
					if (get.tag(card, 'loseCard')) return 0.9;
				}
			},
			noh: true,
			skillTagFilter: function (player, tag) {
				if (tag == 'noh') {
					if (player.hasVisibleCard() > 0) return false;
				}
			}
		}
	},
	"ark_xinhuo": {
		audio: "ext:天灾之下/audio:2",
		trigger: {
			global: "phaseDrawEnd"
		},
		direct: true,
		filter: function (event, player) {
			if (player == event.player) return false;
			return player.hasVisibleCard();
		},
		content: function () {
			"step 0"
			var next = trigger.player.choosePlayerCard(player, 'h');
			next.set('filterButton', function (button) {
				if (!lib.filter.canBeGained(button.link, _status.event.player,
					_status.event.source)) return false;
				return get.is.visible(button.link);
			});
			next.set('ai', function (button) {
				return get.value(button.link) - _status.event.avgValue;
			});
			next.set('prompt', '是否令' + get.translation(player) + '对你发动【薪火】？');
			next.set('prompt2', '摸牌阶段结束时，你可以获得' + get.translation(player) + '一张明置牌，然后其选择弃置你一张牌或令你明置一张牌。');
			next.set('source', player);
			var avgValue = trigger.player.attitudeTo(player) > 0 ? -1 : 0;
			if (avgValue == 0) {
				avgValue = get.value(trigger.player.getCards('he'));
				/*
				var hes=trigger.player.getCards('he');
				if(hes.length){
					for(var c of hes){
						avgValue=Math.max(get.value(c,trigger.player),avgValue);
					}
				}
				*/
			}
			next.set('avgValue', avgValue);
			"step 1"
			if (result.bool) {
				player.logSkill('ark_xinhuo', trigger.player);
				trigger.player.gain(result.cards, player, 'give', 'bySelf');
			} else event.finish();
			"step 2"
			var next = player.discardPlayerCard(trigger.player, 'he');
			next.set('ai', function (button) {
				if (_status.event.att > 0) return 0;
				return get.value(button.link);
			});
			next.set('prompt', '薪火：你可以弃置' + get.translation(trigger.player) + '一张牌');
			next.set('prompt2', '或取消以令其明置一张牌');
			next.set('att', player.attitudeTo(trigger.player));
			"step 3"
			if (!result.bool) {
				if (trigger.player.hasCard(function (card) {
					return !card.isVisible();
				}, 'h')) {
					var next = trigger.player.chooseCard(
						'h', true,
						(card) => !card.isVisible(),
						'薪火：请明置一张非伤害牌'
					);
				}
			} else event.finish();
			"step 4"
			if (result.bool) {
				trigger.player.viewHandcard(result.cards);
			}
		}
	},
	"ark_xiyang": {
		audio: "ext:天灾之下/audio:2",
		unique: true,
		zhuSkill: true,
		contentx: function () {
			"step 0"
			var players = game.filterPlayer(function (current) {
				return player.isSameGroup(current) &&
					current.hasZhuSkill('ark_xiyang') &&
					!current.hasSkill('ark_xiyang_off');
			});
			if (players.length > 1) {
				var next = player.chooseTarget(true);
				next.set('filterTarget', function (card, player, target) {
					return _status.event.targets.contains(target);
				});
				next.set('prompt', '请选择你发动了谁的【熙阳】');
				next.set('targets', players);
			} else event._result = { bool: players.length > 0, targets: players };
			"step 1"
			if (result.bool) {
				event.target = result.targets[0];
				event.target.addTempSkill('ark_xiyang_off', 'phaseUseAfter');
				if (event.target != source) {
					var next = event.target.chooseCard('he');
					next.set('ai', function (card) {
						if (_status.event.att > 0) return get.value(card);
						return -get.value(card);
					});
					next.set('prompt', '熙阳：你可以交给' + get.translation(source) + '一张牌');
					next.set('att', get.attitude(event.target, source));
				} else event.finish();
			} else event.finish();
			"step 2"
			if (result.bool) {
				source.gain(result.cards, event.target, 'giveAuto');
				source.viewHandcard(result.cards);
			}
		},
		global: ["ark_xiyang_2"],
		subSkill: {
			"2": {
				enable: "phaseUse",
				filter: function (event, player) {
					return game.hasPlayer(function (current) {
						return player.isSameGroup(current) &&
							current.hasZhuSkill('ark_xiyang') &&
							!current.hasSkill('ark_xiyang_off');
					}) && game.hasPlayer(function (current) {
						return player.isSameGroup(current) &&
							current.hasVisibleCard();
					});
				},
				chooseButton: {
					dialog: function (event, player) {
						var dialog = ui.create.dialog('【熙阳】请选择要使用的牌', 'hidden');
						game.countPlayer(function (current) {
							if (player.isSameGroup(current) &&
								current.hasVisibleCard()) {
								dialog.add(get.translation(current));
								dialog.add(current.getHandcard());
							}
						});
						return dialog;
					},
					filter: function (button, player) {
						var evt = _status.event.getParent();
						if (evt && evt.filterCard) {
							return evt.filterCard(button.link, player, evt);
						}
						return true;
					},
					check: function (button) {
						var player = get.player();
						if (get.name(button.link) == 'du' && (get.owner(button.link) ? get.attitude(player, get.owner(button.link)) < 1 : true)) return 10;
						if (player.getUseValue(button.link) > 0) return get.order(button.link);
						return -1;
					},
					backup: function (links, player) {
						return {
							filterCard: function () { return false },
							selectCard: -1,
							viewAs: links[0],
							onuse: function (result, player) {
								var next = game.createEvent('ark_xiyangx');
								_status.event.next.remove(next);
								_status.event.after.push(next);
								next.player = player;
								next.source = get.owner(result.card);
								next.setContent(lib.skill['ark_xiyang'].contentx);
							}
						};
					},
					prompt: function (links) {
						return '选择' + get.translation(links) + '的目标';
					}
				},
				ai: {
					order: 1,
					result: { player: 1 }
				},
				sub: true
			},
			off: { sub: true }
		}
	},
