		subSkill: {
			round: { sub: true },
			side: {
				trigger: { global: 'useCardBegin', player: 'damageEnd' },
				filter: function (event, player) {
					if (player.storage.ark_huinu) return false;
					if (event.name == 'useCard') return !player.getSkills(true, true, false).contains('ark_huinu_round') && get.tag(event.card, 'damage');
					return ['ark_huinu_chouhai', 'ark_huinu_benghuai', 'ark_huinu_rechanyuan'].some(function (skill) {
						return !player.getSkills(true, true, false).contains(skill);
					});
				},
				direct: true,
				locked: true,
				content: function () {
					'step 0'
					if (trigger.name == 'useCard') {
						if (!trigger.targets.contains(player)) {
							player.logSkill(event.name);
							trigger.targets.push(player);
						};
						player.addTempSkill('ark_huinu_round', 'roundStart');
						event.finish();
						return;
					};
					var list = ['ark_huinu_chouhai', 'ark_huinu_benghuai', 'ark_huinu_rechanyuan'].filter(function (skill) {
						return !player.getSkills(true, true, false).contains(skill);
					});
					if (list.length) {
						player.chooseControl(list).set('ai', function () {
							var player = get.player(), list = _status.event.list;
							if (player.hp < 3 && list.contains('ark_huinu_benghuai')) return 'ark_huinu_benghuai';
							if (player.countCards('h') > 1 && list.contains('ark_huinu_chouhai')) return 'ark_huinu_chouhai';
							if (list.contains('ark_huinu_rechanyuan')) return 'ark_huinu_rechanyuan';
						}).set('list', list);
						player.logSkill(event.name);
					};
					'step 1'
					if (result.control) {
						var target = _status.currentPhase;
						player.addSkillLog(result.control);
						if (['ark_huinu_chouhai', 'ark_huinu_benghuai', 'ark_huinu_rechanyuan'].every(function (skill) {
							return game.me.getSkills(true, true, false).contains(skill);
						})) {
							player.storage.ark_huinu = true;
							if (!player.isMaxHandcard(true)) player.drawTo(game.findPlayer(function (current) {
								return current.isMaxHandcard();
							}).countCards('h') + 1);
							player.trySkillAnimate(event.subname() + '_animate');
						};
						player.recover();
						if (target && target != player) {
							if (target.countCards('he')) {
								player.line(target, 'green');
								target.chooseCard(2, 'he', '恚怒:交给' + get.translation(player) + '两张牌', true).set('ai', function (card) {
									var player = get.player(), target = _status.event.target, order = get.order(card, player);
									if (get.attitude(player, target) > 1) return -order;
									return -get.value(card);
								}).set('target', player);
							};
						};
					};
					'step 2'
					if (result.cards) {
						player.gain(result.cards, _status.currentPhase, 'giveAuto');
					};
				}
			},
			benghuai: {
				inherit: 'benghuai',
				audio: 'ext:天灾之下/audio:2',
				audioname: undefined,
			},
			chouhai: {
				inherit: 'chouhai',
				audio: 'ext:天灾之下/audio:2',
			},
			rechanyuan: {
				inherit: 'rechanyuan',
				skillBlocker: function (skill, player) {
					return skill != 'chanyuan' && skill != 'rechanyuan' && skill != 'ark_huinu_rechanyuan' && !lib.skill[skill].charlotte && player.hp <= 1;
				},
				intro: {
					content: function (storage, player, skill) {
						var str = '<li>锁定技，当你的体力值不大于1时，你的其他技能失效。';
						var list = player.getSkills(null, false, false).filter(function (i) {
							return lib.skill.rechanyuan.skillBlocker(i, player);
						});
						if (list.length) str += ('<br><li>失效技能：' + get.translation(list))
						return str;
					},
				},
			},
			animate: {
				skillAnimation: true,
				animationColor: 'gray',
				sub: true,
			},
		},
