	"ark_hunyin": {
		trigger: {
			global: "phaseZhunbeiBegin",
		},
		skillAnimation: true,
		animationColor: "key",
		juexingji: true,
		unique: true,
		forced: true,
		filter: function (event, player) {
			var players = game.filterPlayer()
			var hp = players[0].hp
			for (var i = 0; i < players.length; i++) {
				if (players[i].hp != hp) return false
			}
			return true
		},
		content: function () {
			"step 0"
			event.current = player.next;
			event.currented = [];
			"step 1"
			event.currented.push(event.current);
			event.current.animate('target');
			event.current.chooseToUse('魂音：使用一张杀或失去一点体力', function (card) {
				if (get.name(card) != 'sha') return false;
				return lib.filter.filterCard.apply(this, arguments)
			}, function (card, player, target) {
				if (player == target) return false;
				var dist = get.distance(player, target);
				if (dist > 1) {
					if (game.hasPlayer(function (current) {
						return current != player && get.distance(player, current) < dist;
					})) {
						return false;
					}
				}
				return lib.filter.filterTarget.apply(this, arguments)
			}).set('ai2', function () {
				return get.effect_use.apply(this, arguments) + 0.01;
			});
			"step 2"
			if (result.bool == false) event.current.loseHp();
			event.current = event.current.next;
			if (event.current != player && !event.currented.contains(event.current)) {
				game.delay(0.5);
				event.goto(1);
			}
			'step 3'
			player.die();
		},
	},
	"ark_guaiqiao": {
		trigger: {
			global: "phaseBegin",
		},
		direct: true,
		usable: 1,
		filter: function (event, player) {
			if (player == event.player && game.hasPlayer(function (current) {
				return player.inRange(current);
			})) return false;
			return player.inRange(event.player);
		},
		content: function () {
			'step 0'
			trigger.player.chooseControl().set('choiceList', [
				'跳过摸牌阶段并对' + get.translation(player) + '造成一点伤害',
				'跳过出牌阶段和弃牌阶段',
				'取消',
			]).set('ai', function () {
				if (get.attitude(trigger.player, player) < -1 && trigger.player.countCards('h') >= trigger.player.maxHp) return 0;
				if (get.attitude(trigger.player, player) > 0) return 2;
				return 1;
			});
			'step 1'
			if (result.index == 0) {
				player.damage(trigger.player)
				trigger.player.skip('phaseDraw')
			} else if (result.index == 1) {
				trigger.player.skip('phaseUse')
				trigger.player.skip('phaseDiscard')
			}
			else if (result.index == 2) event.finish()
		},
	},
