				game.addVideo('delay', null, 2);
				game.delay(1.5);
				"step 1"
				game.broadcastAll('closeDialog', event.videoId);
				player.gain(event.cards, 'draw', 'log');
				"step 2"
				var count = event.cards.filter((cardx) => get.type(cardx) != 'basic').length;
				if (count) player.chooseToDiscard('h', count, true);
