	"ark_zongma": {
		//audio:"ext:天灾之下/audio:2",
		trigger: {
			player: "phaseBefore"
		},
		priority: -1,
		check: function (event, player) {
			if (player.countCards('e', function (card) {
				return get.tag(card, 'skip') != undefined;
			})) return true;
			return !player.needsToDiscard();
		},
		content: function () {
			"step 0"
			var stageList = get.TZZXStageCut(trigger.content);
			var i = 0, j = stageList.length;
			var mainStage = ['phaseJudge', 'phaseDraw', 'phaseUse', 'phaseDiscard'];
			while (i != j) {
				while (i < j) {
					i++;
					var isFind = false;
					for (var stage of mainStage) {
						if (stageList[i].indexOf(stage) != -1) {
							isFind = true;
							break;
						}
					}
					if (isFind) break;
				}
				while (i < j) {
					j--;
					var isFind = false;
					for (var stage of mainStage) {
						if (stageList[j].indexOf(stage) != -1) {
							isFind = true;
							break;
						}
					}
					if (isFind) break;
				}
				var temp = stageList[i];
				stageList[i] = stageList[j];
				stageList[j] = temp;
			}
			var str = get.TZZXStagePaste(stageList, true);
			trigger.content = (
				new Function('event', 'step', 'source', 'player', 'target', 'targets',
					'card', 'cards', 'skill', 'forced', 'num', 'trigger', 'result',
					'_status', 'lib', 'game', 'ui', 'get', 'ai', str)
			);
			"step 1"
			player.addTempSkill('ark_zongma_reversePhase');

		},
		ai: {
			effect: {
				target: function (card, player, target, current) {
					if (get.tag(card, 'skip')) {
						return [0.5, 0];
					}
				}
			}
		},
		subSkill: { reversePhase: { sub: true } }
	},

