				intro: {
					name: "裂潮",
					content: "players"
				},
				mod: {
					playerEnabled: function (card, player, target) {
						if (player.storage['ark_liechao_ark_zhizheng'].contains(target)) return false;
					}
				},
				init: function (player) {
					player.storage['ark_liechao_ark_zhizheng'] = [];
				},
				onremove: function (player) {
					delete player.storage['ark_liechao_ark_zhizheng'];
				},
