	"ark_linjue": {
		audio: '声音',
		enable: 'phaseUse',
		usable: 1,
		prompt: '视为使用一张【决斗】',
		viewAs: {
			name: 'juedou',
			isCard: true,
			storage: {
				nowuxie: true,
			},
		},
		filterCard: () => false,
		selectCard: -1,
		log: false,
		precontent: function () {
			player.logSkill(event.name);
		},
		ai: {
			order: function () {
				return get.order({ name: 'juedou' }) - 0.5;
			},
		},
		group: ['ark_linjue_record', 'ark_linjue_damage'],
		subSkill: {
			record: {
				init: function (player) {
					player.storage.ark_jirui_pnum = 0;
					player.storage.ark_jirui_tnum = 0;
				},
				forced: true,
				popup: false,
				silent: true,
				trigger: {
					global: 'damageEnd',
				},
				filter: function (event, player) {
					var evt = event.getParent();
					return evt && evt.name == 'juedou' && evt.skill == 'ark_linjue';
				},
				content: function () {
					'step 0'
					var evt = trigger.getParent();
					event.pcards = evt[player == evt.player ? 'playerCards' : 'targetCards'].slice(0);
					for (var i = 0; i < event.pcards.length; i++) {
						if (get.position(event.pcards[i]) != 'd') event.pcards.remove(event.pcards[i--]);
					}
					event.tcards = evt[player == evt.player ? 'targetCards' : 'playerCards'].slice(0);
					for (var i = 0; i < event.tcards.length; i++) {
						if (get.position(event.tcards[i]) != 'd') event.tcards.remove(event.tcards[i--]);
					}
					'step 1'
					for (var card of event.pcards) {
						player.storage.ark_jirui_pnum += get.number(card);
					}
					for (var card of event.tcards) {
						player.storage.ark_jirui_tnum += get.number(card);
					}
				},
			},
			damage: {
				forced: true,
				trigger: {
					player: 'useCardAfter',
				},
				filter: function (event, player) {
					if (player.storage.ark_jirui_pnum == player.storage.ark_jirui_tnum) {
						player.storage.ark_jirui_pnum = 0;
						player.storage.ark_jirui_tnum = 0;
					}
					return event.skill == 'ark_linjue' && (player.storage.ark_jirui_pnum != 0 || player.storage.ark_jirui_tnum != 0) && event.targets[0].isAlive();
				},
				content: function () {
					if (player.storage.ark_jirui_pnum > player.storage.ark_jirui_tnum) {
						trigger.targets[0].damage('nocard').source = player;
					} else {
						player.damage('nocard').source = trigger.targets[0];
					}
					player.storage.ark_jirui_pnum = 0;
					player.storage.ark_jirui_tnum = 0;
				},
			},
		},
	},
	"ark_tongtu": {
		init: function (player) {
			player.storage.ark_tongtu = false;
			player.storage.ark_tongtu_win = 0;
		},
		audio: '声音',
		trigger: {
			player: 'phaseEnd',
		},
		direct: true,
		unique: true,
		limited: true,
		skillAnimation: true,
		animationColor: 'orange',
		forceunique: true,
		filter: function (event, player) {
			return player.countCards('h') && game.hasPlayer((current) => current != player && player.canCompare(current)) && !player.storage.ark_tongtu;
		},
		content: function () {
			'step 0'
			player.chooseTarget([1, 3], get.prompt2(event.name), '是否选择至多三名角色进行拼点？', function (card, player, target) {
				return player != target && player.canCompare(target);
			}).ai = function (target) {
				var player = _status.event.player;
				return get.attitude(player, target) < 0;
			};
			'step 1'
			if (result.bool) {
				event.targets = result.targets;
				player.awakenSkill(event.name);
				player.logSkill(event.name, event.targets);
				player.storage.ark_tongtu = true;
				player.chooseToCompare(event.targets).callback = lib.skill.ark_tongtu.callback;
				game.delay();
			}
			'step 2'
			if (player.storage.ark_tongtu_win == 0) event.goto(4);
			'step 3'
			var win = player.storage.ark_tongtu_win;
			for (var target of event.targets) {
				if (target.countGainableCards(player, 'he')) {
					player.gainPlayerCard(target, 'he', [1, win], true);
				}
			}
			if (!game.hasPlayer((current) => current != player && !event.targets.contains(current))) event.finish();
			'step 4'
			player.chooseCardTarget({
				forced: true,
				filterCard: true,
				selectCard: [1, player.countCards('h')],
				filterTarget: function (card, player, target) {
					return player != target && !event.targets.contains(target);
				},
				ai1: function (card) {
					if (ui.selected.cards.length > 0) return -1;
					if (card.name == 'du') return 20;
					return (_status.event.player.countCards('h') - _status.event.player.hp);
				},
				ai2: function (target) {
					var att = get.attitude(_status.event.player, target);
					if (ui.selected.cards.length && ui.selected.cards[0].name == 'du') {
						if (target.hasSkillTag('nodu')) return 0;
						return 1 - att;
					}
					return att - 4;
				},
				prompt: '请选择要送人的卡牌'
			});
			'step 5'
			if (result.bool) {
				player.line(result.targets, 'green');
				result.targets[0].gain(result.cards, player, 'giveAuto');
			}
			'step 6'
			if (player.countCards('h')) event.goto(4);
		},
		callback: function () {
			if (event.num1 > event.num2) {
				player.storage.ark_tongtu_win++;
			}
		},
		mark: true,
		intro: {
			content: 'limited',
		},
	},
