				var history = player.getHistory('lose', function (evt, card) {
					for (var i of evt.cards) {
						return get.position(i, true) == "d" && get.type(i) == 'red'
					}
				});
				var history1 = player.getHistory('gain', function (evt, player) {
					for (var i of evt.cards) {
						return player.getCards('h').contains(i) && get.type(i) == 'basic'
					}
				});
				if (history.length > 0 && event.filterCard({ name: 'shan', isCard: true }, player, event)) list.push(['基本', '', 'shan']);
				if (history1.length > 0 && event.filterCard({ name: 'sha', isCard: true }, player, event)) list.push(['基本', '', 'sha']);
